files.css:
.bar {
  display: flex;
  gap: 1rem;
  padding: 0.75rem 1rem;
  background: #1e293b;
  font-family: sans-serif;
}
.bar a { color: #93c5fd; text-decoration: none; }

.grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 12px;
  padding: 1rem;
  font-family: sans-serif;
}
.item {
  background: #dbeafe;
  padding: 2rem;
  text-align: center;
  border-radius: 8px;
}

starter.css:
.center-wrap {
  min-height: 200px;
  /* add flex centering */
}
.centered {
  padding: 1.5rem 2rem;
  background: #22c55e;
  color: #fff;
  border-radius: 8px;
  font-family: sans-serif;
}
